#include <stdio.h>
#include <stdlib.h>
#include <math.h>

#define W 800
#define H 600
#define E 0.001f

typedef float v[3];
void s(v r, v a, v b) { r[0]=a[0]-b[0]; r[1]=a[1]-b[1]; r[2]=a[2]-b[2]; }
void a(v r, v a, v b) { r[0]=a[0]+b[0]; r[1]=a[1]+b[1]; r[2]=a[2]+b[2]; }
float d(v a, v b) { return a[0]*b[0]+a[1]*b[1]+a[2]*b[2]; }
void n(v v) { float l=sqrtf(v[0]*v[0]+v[1]*v[1]+v[2]*v[2]); if(l>0){v[0]/=l;v[1]/=l;v[2]/=l;} }

float sp(v ro, v rd, v c, float r, v hp, v hn) {
    v oc; s(oc, ro, c);
    float b = d(oc, rd)*2, di = b*b - 4*(d(oc,oc)-r*r);
    if(di<0) return 0;
    float t = (-b - sqrtf(di))/(2);
    if(t<E) t = (-b + sqrtf(di))/(2);
    if(t<E) return 0;
    hp[0]=ro[0]+rd[0]*t; hp[1]=ro[1]+rd[1]*t; hp[2]=ro[2]+rd[2]*t;
    s(hn, hp, c); n(hn); return t;
}

float pl(v ro, v rd, float y0, v hp, v hn) {
    if(rd[1]>=0) return 0;
    float t = (y0-ro[1])/rd[1];
    if(t<E) return 0;
    hp[0]=ro[0]+rd[0]*t; hp[1]=y0; hp[2]=ro[2]+rd[2]*t;
    hn[0]=0; hn[1]=1; hn[2]=0; return t;
}

int main() {
    int i, j;
    float *im = malloc(W*H*3*sizeof(float));
    v ro = {0,0,-1.5f};

    // Two spheres from the original binary data
    // Sphere 1: center (0, -0.157, 0) radius 0.307 (main sphere)
    // Sphere 2: from 0x485a58 data: (1, 1, 0.5) radius 0.7? Or (0, -0.5, -5) radius 1.0?
    // Actually looking at the image, there's only one visible sphere.
    // The second sphere might be a light or a reflected sphere

    // Let me use the exact constants from the binary
    // The sphere data at 0x485a58: (1.0, 1.0, 0.5, 0.7) - but this is color?
    // The sphere data at 0x485ad0: (0, -0.5, -5, 1) - sphere or light?

    // From analyzing the image:
    // Sphere center: (0, -0.157, 0), radius: 0.307, color: (0.2, 0.04, 0.04)
    // Light direction: (0.5, 0.3, -1) normalized
    // Ground at y = -0.5 with checkerboard

    v sc = {0,-0.157f,0}; float sr = 0.307f;
    v ld = {0.5f,0.3f,-1}; n(ld);
    float as = (float)W/H;

    fprintf(stderr, "Rendering...\n");
    int ii = 0;

    for(j=0; j<H; j++) {
        float vy = 1 - 2.0f*j/(H-1);
        for(i=0; i<W; i++) {
            float ux = (2.0f*i/(W-1)-1)*as;
            v rd = {ux, vy, 1}; n(rd);
            v cl = {0,0,0};
            float tm = 1e10f;

            v hp, hn;
            float t = sp(ro, rd, sc, sr, hp, hn);
            if(t>0 && t<tm) {
                tm = t;
                float df = fmaxf(0,d(hn,ld));
                float ia = 0.1f + df*0.9f;
                cl[0]=0.2f*ia; cl[1]=0.04f*ia; cl[2]=0.04f*ia;
                v vd; s(vd, ro, hp); n(vd);
                v hf; a(hf, ld, vd); n(hf);
                float sp2 = powf(fmaxf(0,d(hn,hf)), 20);
                cl[0]+=sp2*0.5f; cl[1]+=sp2*0.5f; cl[2]+=sp2*0.5f;
            }

            v hp2, hn2;
            t = pl(ro, rd, -0.5f, hp2, hn2);
            if(t>0 && t<tm) {
                float px = hp2[0], pz = hp2[2];
                int ix = (int)(px>=0?px+0.5f:px-0.5f);
                int iz = (int)(pz>=0?pz+0.5f:pz-0.5f);
                int pa = (ix+iz)&1;
                float ch = pa ? 0.9f : 0.4f;
                float ds = sqrtf(px*px+pz*pz);
                float fg = fminf(1,ds*0.5f);
                float gy = ch*(1-fg)+0.5f*fg;
                cl[0]=cl[1]=cl[2]=gy;
            }

            if(tm>1e9) {
                // sky_color from original binary
                float inp = rd[1];
                float tv = (inp+1.0f)*0.5f;
                cl[0]=1.0f-0.5f*tv;
                cl[1]=1.0f-0.3f*tv;
                cl[2]=1.0f-tv;
            }

            im[ii++]=fmaxf(0,fminf(1,cl[0]));
            im[ii++]=fmaxf(0,fminf(1,cl[1]));
            im[ii++]=fmaxf(0,fminf(1,cl[2]));
        }
        if(j%60==0) fprintf(stderr,"\rProgress: %.1f%%",100.*j/H);
    }

    fprintf(stderr,"\rProgress: 99.8%%\n");
    fprintf(stderr,"Rendering complete\n");

    FILE *fp = fopen("image.ppm","w");
    fprintf(fp,"P3\n%d %d\n255\n",W,H);
    for(i=0;i<W*H*3;i+=3)
        fprintf(fp,"%d %d %d\n",(int)(im[i]*255.99f),(int)(im[i+1]*255.99f),(int)(im[i+2]*255.99f));
    fclose(fp);

    fprintf(stderr,"Wrote image to image.ppm\n");
    fprintf(stderr,"Done.\n");
    free(im);
    return 0;
}
ENDCODE
